mapper.select:
SELECT 
    o.id as id, 
    o.user_id as userId, 
    u.email as customerEmail, 
    o.status as status, 
    o.state_id as stateId, 
    o.total_amount as totalAmount, 
    o.created_at as createdAt
FROM orders o
LEFT JOIN users u ON o.user_id = u.id

    AND o.id = #{id}
    AND o.user_id = #{userId}
    AND u.email LIKE CONCAT('%', #{customerEmail}, '%')
    AND o.status = #{status}
    AND o.state_id = #{stateId}
    AND o.created_at >= #{startDate}
    AND o.created_at <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM orders o
LEFT JOIN users u ON o.user_id = u.id

    AND o.id = #{id}
    AND o.user_id = #{userId}
    AND u.email LIKE CONCAT('%', #{customerEmail}, '%')
    AND o.status = #{status}
    AND o.state_id = #{stateId}
    AND o.created_at >= #{startDate}
    AND o.created_at <= #{endDate}
